const payload = $input.item.json.body;
const meetingId = String(payload.payload?.object?.id || '');

if (!meetingId) throw new Error('No meeting ID found in meeting.ended payload');

const staticData = $getWorkflowStaticData('global');
const session = staticData.meetings?.[meetingId];

if (!session) {
  throw new Error('Meeting ' + meetingId + ' not found in static data. Was Flow 1 active when this meeting started?');
}

return [{
  json: {
    meetingId,
    bot1Id: session.bot1Id,
    bot2Id: session.bot2Id,
    bot3Id: session.bot3Id,
    sessionTitle: session.sessionTitle,
    sessionDate: session.sessionDate
  }
}];

const { bot1Id, bot2Id, bot3Id, sessionTitle, sessionDate, meetingId } = $input.item.json;

function extractUrl(bot) {
  const recordings = bot.recordings || [];
  if (recordings.length === 0) return null;
  const s = recordings[0].media_shortcuts || {};
  return s?.video_mixed_mp4?.data?.download_url ||
    s?.video_mixed?.data?.download_url ||
    s?.speaker_timeline_video?.data?.download_url ||
    bot.video_url || null;
}

async function getBot(botId) {
  return await $helpers.httpRequest({
    method: 'GET',
    url: `https://us-west-2.recall.ai/api/v1/bot/${botId}/`,
    headers: { Authorization: 'Token CHANGE_THIS_RECALL_API_TOKEN' }
  });
}

const bot1 = await getBot(bot1Id);
const bot2 = await getBot(bot2Id);
const bot3 = await getBot(bot3Id);

const url1 = extractUrl(bot1);
const url2 = extractUrl(bot2);
const url3 = extractUrl(bot3);

if (!url1) throw new Error('Bot 1 recording not ready after 20 min — try increasing the wait time or check Recall dashboard');

return [{
  json: {
    meetingId,
    sessionTitle,
    sessionDate,
    recording_url_1: url1 || '',
    recording_url_2: url2 || '',
    recording_url_3: url3 || ''
  }
}];
